  // the activity line (no 'Cesar responding… · thinking…' contradiction). Falls
  // back to 'thinking' for an absent/unknown verb.
  let label = (phase && typeof phase.wait === 'string' && phase.wait.length > 0) ? phase.wait : 'thinking';
